import requests

KONG_ADMIN_URL = 'http://localhost:8001'

def create_service(name, url):
    response = requests.post(f'{KONG_ADMIN_URL}/services', json={
        'name': name,
        'url': url
    })
    return response.json()

def create_route(service_name, paths):
    response = requests.post(f'{KONG_ADMIN_URL}/services/{service_name}/routes', json={
        'paths': paths
    })
    return response.json()

def create_upstream(name):
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams', json={
        'name': name
    })
    return response.json()

def add_target(upstream_name, target, weight=100):
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams/{upstream_name}/targets', json={
        'target': target,
        'weight': weight
    })
    return response.json()

def configure_kong():
    service = create_service('example-service', 'http://example.com')
    create_route(service['name'], ['/example'])
    upstream = create_upstream('example-upstream')
    add_target(upstream['name'], 'example.com:80')

if __name__ == '__main__':
    configure_kong()